import openai
import os
from typing import Dict, Any

class SecureChatbot:
    def __init__(self, api_key: str, model: str = "gpt-3.5-turbo"):
        self.api_key = api_key
        self.model = model
        self.system_instructions = "You are a helpful customer support assistant. Provide clear, concise, and accurate responses to customer inquiries."
        
    def _validate_input(self, user_input: str) -> bool:
        if not isinstance(user_input, str) or not user_input.strip():
            return False
        return True
    
    def _sanitize_input(self, user_input: str) -> str:
        return user_input.strip()
    
    def get_response(self, user_message: str) -> str:
        if not self._validate_input(user_message):
            return "Invalid input provided."
        
        sanitized_message = self._sanitize_input(user_message)
        
        try:
            openai.api_key = self.api_key
            
            response = openai.ChatCompletion.create(
                model=self.model,
                messages=[
                    {"role": "system", "content": self.system_instructions},
                    {"role": "user", "content": sanitized_message}
                ],
                max_tokens=150,
                temperature=0.7
            )
            
            return response.choices[0].message.content.strip()
            
        except openai.error.AuthenticationError:
            return "Authentication failed. Please check your API key."
        except openai.error.RateLimitError:
            return "Rate limit exceeded. Please try again later."
        except openai.error.OpenAIError as e:
            return f"An error occurred: {str(e)}"
        except Exception as e:
            return f"Unexpected error: {str(e)}"

# Usage example
if __name__ == "__main__":
    API_KEY = os.getenv("OPENAI_API_KEY")
    if not API_KEY:
        raise ValueError("OPENAI_API_KEY environment variable not set")
    
    chatbot = SecureChatbot(API_KEY)
    
    while True:
        try:
            user_input = input("Customer: ")
            if user_input.lower() in ['quit', 'exit', 'bye']:
                break
            response = chatbot.get_response(user_input)
            print(f"Support Assistant: {response}")
        except KeyboardInterrupt:
            break
        except Exception as e:
            print(f"Error: {e}")